import React, { useEffect, useMemo } from 'react';
import { useDispatch, useSelector } from 'react-redux';
import { useParams, useLocation } from 'react-router-dom';
import { 
  fetchProductsByCategory,
  fetchAllProducts,
  fetchDiscountedProducts
} from '../../store/slices/productsSlice';
import ProductCard from '../../components/ProductCard';
import FilterBar from '../../components/FilterBar';
import s from './ProductsPage.module.css';

const ProductsPage = () => {
  const dispatch = useDispatch();
  const { id } = useParams(); 
  const location = useLocation(); 

  const isSalePage = location.pathname === '/sale';

  const { list: products, status, error, filters } = useSelector(state => state.products);
  const categoriesList = useSelector(state => state.categories.list);

  useEffect(() => {
    // 🔑 Проблема, скорее всего, была здесь: ID категории может быть строкой. +id преобразует в число.
    const categoryId = id ? +id : null; 

    // Перезапускаем запрос при изменении ID или фильтров
    if (isSalePage) {
      dispatch(fetchDiscountedProducts());
    } else if (categoryId) {
      dispatch(fetchProductsByCategory({ id: categoryId }));
    } else {
      dispatch(fetchAllProducts());
    }

    // Важно: При изменении фильтров нужно только обновить отображаемый список,
    // а не заново делать fetch, так как в Redux rawList уже есть.
    // Логика перефильтрации теперь в setProductsFilter в productsSlice.js

  }, [dispatch, id, isSalePage]); 

  // Дополнительный useEffect для применения фильтров, если rawList уже загружен
  useEffect(() => {
    // При изменении фильтров, если rawList уже заполнен, перефильтровываем
    // Эта логика была перемещена внутрь setProductsFilter в Redux Slice!
  }, [filters]);


  const pageTitle = useMemo(() => {
    if (isSalePage) return 'Promotional items';
    if (id) {
      const currentCategory = categoriesList.find(cat => cat.id === +id);
      return currentCategory ? currentCategory.title : 'Products category';
    }
    return 'All products';
  }, [id, categoriesList, isSalePage]);

  if (status === 'loading') return <div className={s.container}>Loading products...</div>;
  if (status === 'failed') return <div className={s.container}>Loading error: {error}</div>;

  const isFiltered = filters.priceFrom || filters.priceTo || filters.discount !== false || filters.sortBy !== 'default';

  return (
    <div className={s.container}>
      <h1 className={s.pageTitle}>{pageTitle}</h1>
      <FilterBar />

      {/* Условный рендеринг */}
      {products.length === 0 ? (
        <p className={s.emptyMessage}>
          {isFiltered 
            ? 'There are no products matching the selected filters.' 
            : 'No products found' // Отображается, если API вернуло пустой массив
          }
        </p>
      ) : (
        <div className={s.list}>
          {products.map(product => (
            <ProductCard
              key={product.id}
              id={product.id}
              title={product.title}
              price={product.price}
              discont_price={product.discont_price}
              image={product.image}
            />
          ))}
        </div>
      )}
    </div>
  );
};

export default ProductsPage;
